# Geometry utilities module with shapes and calculation functions
# NOTE: math module is not available - using direct calculations

class Shape:
    @abstract
    def area(self) -> float: ...

    @abstract
    def perimeter(self) -> float: ...

class Rectangle(Shape):
    width: float
    height: float

    def __init__(self, width: float, height: float):
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

class Circle(Shape):
    radius: float

    def __init__(self, radius: float):
        self.radius = radius

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self.radius

def total_area(shapes: list[Shape]) -> float:
    total: float = 0.0
    for shape in shapes:
        total += shape.area()
    return total

def average_perimeter(shapes: list[Shape]) -> float:
    if len(shapes) == 0:
        return 0.0
    total: float = 0.0
    for shape in shapes:
        total += shape.perimeter()
    return total / float(len(shapes))
